select 
  ct.*,
  (select member_nickname from member where member_id = comment_member_id) as comment_member_nickname,
  (select member_profile_img from member where member_id = comment_member_id) as comment_member_profile_img
from comment_tbl ct
where comment_type = #{commentType} 

  and comment_board_no = #{targetNo}


  and comment_userpick_no = #{targetNo}

and comment_parent_no is null order by 1

